SELECT data_year_month AS month, COALESCE(SUM(amount_rmb), 0) AS amount FROM trade_data WHERE deleted = 0 AND data_year_month IS NOT NULL AND data_year_month != ''
AND data_year_month >= #{startMonth}
AND data_year_month <= #{endMonth}
GROUP BY data_year_month ORDER BY data_year_month ASC

SELECT #{startMonth} AS startMonth, #{endMonth} AS endMonth, #{keyword} AS keyword, COUNT(1) AS recordCount, COALESCE(SUM(amount_rmb), 0) AS totalAmountRmb FROM trade_data WHERE deleted = 0
AND (product_name LIKE CONCAT('%', #{keyword}, '%') OR partner_name LIKE CONCAT('%', #{keyword}, '%'))
AND data_year_month >= #{startMonth}
AND data_year_month <= #{endMonth}

SELECT data_year_month AS month, COALESCE(SUM(amount_rmb), 0) AS amount FROM trade_data WHERE deleted = 0 AND data_year_month IS NOT NULL AND data_year_month != ''
AND (product_name LIKE CONCAT('%', #{keyword}, '%') OR partner_name LIKE CONCAT('%', #{keyword}, '%'))
AND data_year_month >= #{startMonth}
AND data_year_month <= #{endMonth}
GROUP BY data_year_month ORDER BY data_year_month ASC

SELECT trade_mode_name AS tradeModeName, COUNT(1) AS count, COALESCE(SUM(amount_rmb), 0) AS totalAmount FROM trade_data WHERE deleted = 0 AND trade_mode_name IS NOT NULL AND trade_mode_name != ''
AND (product_name LIKE CONCAT('%', #{keyword}, '%') OR partner_name LIKE CONCAT('%', #{keyword}, '%'))
AND data_year_month >= #{startMonth}
AND data_year_month <= #{endMonth}
GROUP BY trade_mode_name ORDER BY totalAmount DESC

SELECT partner_name AS name, COALESCE(SUM(amount_rmb), 0) AS value FROM trade_data WHERE deleted = 0 AND partner_name IS NOT NULL AND partner_name != ''
AND (product_name LIKE CONCAT('%', #{keyword}, '%') OR partner_name LIKE CONCAT('%', #{keyword}, '%'))
AND data_year_month >= #{startMonth}
AND data_year_month <= #{endMonth}
GROUP BY partner_name ORDER BY value DESC LIMIT #{limit}
